1	/**
2	 * Cursor-based pagination utilities for Fastify routes.
3	 *
4	 * Usage example:
5	 *
6	 *   import { paginationQuerySchema, paginatedResponse, decodeCursor, encodeCursor } from './pagination.js'
7	 *
8	 *   fastify.get<{ Querystring: { limit?: number; cursor?: string } }>('/api/items', {
9	 *     schema: { querystring: paginationQuerySchema, ... }
10	 *   }, async (request) => {
11	 *     const limit = request.query.limit ?? 20
12	 *     const after = request.query.cursor ? decodeCursor(request.query.cursor) : null
13	 *     // e.g.: const rows = await db.query('SELECT * FROM items WHERE id > $1 ORDER BY id LIMIT $2', [after?.id ?? 0, limit + 1])
14	 *     const items = rows.slice(0, limit)
15	 *     const nextCursor = rows.length > limit ? encodeCursor({ id: items[items.length - 1].id }) : null
16	 *     return paginatedResponse(items, nextCursor)
17	 *   })
18	 */
19	
20	export const paginationQuerySchema = {
21	  type: 'object',
22	  properties: {
23	    limit: {
24	      type: 'integer',
25	      minimum: 1,
26	      maximum: 100,
27	      default: 20
28	    },
29	    cursor: {
30	      type: 'string',
31	      description: 'Opaque cursor for the next page, returned by the previous response'
32	    }
33	  }
34	} as const
35	
36	/**
37	 * Wraps a page of results in a standard pagination envelope.
38	 */
39	export function paginatedResponse<T>(items: T[], nextCursor: string | null) {
40	  return {
41	    data: items,
42	    pagination: {
43	      nextCursor,
44	      hasMore: nextCursor !== null
45	    }
46	  }
47	}
48	
49	/**
50	 * Encodes a cursor value as a base64url JSON string, keeping internals opaque to clients.
51	 */
52	export function encodeCursor(value: Record<string, unknown>): string {
53	  return Buffer.from(JSON.stringify(value)).toString('base64url')
54	}
55	
56	/**
57	 * Decodes a cursor produced by encodeCursor back to its original object.
58	 * Pass a `validate` callback to reject payloads with unexpected shapes (throws 400).
59	 */
60	export function decodeCursor(
61	  cursor: string,
